SELECT * FROM dairy_data.dairy_details;
use dairy_data;
-- 1.Total revenue generated by each product?
select product_name, sum(Revenue) as Total_Revenue from dairy_details group by product_name;

-- 2.Give Brand with highest total revenue?
select brand, sum(Revenue) as Total_Revenue from dairy_details group by brand order by Total_Revenue desc limit 1;

-- 3.Give monthly revenue trend across all products?
select date_format(order_date, '%Y_%m') as month,product_name, sum(revenue) from dairy_details group by date_format(order_date, '%Y_%m'),product_name order by month;

-- 4.Products below the minimum stock threshold?
select product_name,Quanttity_stock,minimum_stock_threshold from dairy_details where Quanttity_stock < minimum_stock_threshold;

-- 5.Total reorder quantity required per product?
select product_name,(minimum_stock_threshold-Quanttity_stock) as recorder_quantity from dairy_details where Quanttity_stock < minimum_stock_threshold ;

-- 6.which sales channel generates the most revenue?
select sales_channel, sum(revenue) as most_revenue from dairy_details group by sales_channel order by most_revenue desc limit 1;

-- 7.top 5 customer location by puchase volumne?
select customer_location, sum(Quantity_sold) as purchase_volumne from dairy_details group by customer_location order by purchase_volumne desc limit 5;

-- 8.Average selling price per product?
select product_name, avg(selling_price) as Average_selling_price from dairy_details group by product_name;

-- 9.Compare selling price with listed price?
select product_name,selling_price,price_per_unit, (selling_price-price_per_unit) as compare_price from dairy_details;

-- 10.Product with less than 10 days shelf life remaining?
select product_name,shelf_life from dairy_details where shelf_life <10;


-- 11.Average shelf life by product category?
select product_name, avg(shelf_life) as Average_shelf_life from dairy_details group by product_name;

-- 12.Average number of cows per farm size category?
select farm_size, avg(number_of_cows) as Average_cows from dairy_details group by farm_size;

-- 13.location with the largest total land area?
select location, max(total_land_area) as largest_land_area from dairy_details group by location order by largest_land_area desc;

-- 14.Top 3 locations by average production quantity?
select location, avg(Quantity) as Average_quantity from dairy_details group by location order by Average_quantity desc limit 3;

-- 15.Calculate profit for each product?
select product_name, sum((selling_price - price_per_unit) * Quantity_sold) as profit from dairy_details where (selling_price - price_per_unit) * Quantity_sold >=0 
group by product_name;

-- 16. Most profitbale Brand overall?
SELECT 
    brand,
    SUM((selling_price - price_per_unit) * Quantity_sold) AS profitable_brand
FROM
    dairy_details
WHERE
    (selling_price - price_per_unit) * Quantity_sold >= 0
GROUP BY brand
ORDER BY profitable_brand DESC
LIMIT 1;
-- 17. Yearly revenue growth?
 select year(Order_date), sum(Revenue) as Yearly_revenue_Growth from dairy_details group by year(Order_date);
 
 -- 18.Best-selling product each year?
 select year(Order_date), product_name, sum(Revenue) as revenue from dairy_details group by year(Order_date), product_name order by revenue desc;
 
 -- 19. Products that need immediate restock?
 select product_name,Quanttity_stock,minimum_stock_threshold, (minimum_stock_threshold-Quanttity_stock) as restock from dairy_details 
 where Quanttity_stock <= minimum_stock_threshold;
 
 -- 20.Identify expired products still in stock?
 select product_name,Order_date, expiration_date, Quanttity_stock from dairy_details where expiration_date < Order_date and Quanttity_stock > 0;
 
 -- 21.Average shelf life per brand?
 select brand, avg(shelf_life) as Average_shelf_life from dairy_details group by brand ;
 
 -- 22.Most popular product in each customer location?
 select customer_location, product_name, sum(Quanttity_stock) as total_quantity 
 from dairy_details group by customer_location, product_name
 order by total_quantity desc limit 1;